import{_ as i,o as e,c as l,ag as n}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Colocación y Distribución","description":"","frontmatter":{},"headers":[],"relativePath":"es/industrial-practices/lighting/placement-distribution.md","filePath":"es/industrial-practices/lighting/placement-distribution.md"}'),o={name:"es/industrial-practices/lighting/placement-distribution.md"};function r(s,a,c,t,d,u){return e(),l("div",null,[...a[0]||(a[0]=[n('<h1 id="colocacion-y-distribucion" tabindex="-1">Colocación y Distribución <a class="header-anchor" href="#colocacion-y-distribucion" aria-label="Permalink to &quot;Colocación y Distribución&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>La colocación y distribución se refieren a cómo se posicionan las luminarias y cómo se distribuye la luz en un espacio industrial.</p><p>La colocación adecuada asegura que la iluminación se entregue donde se necesita, mientras que la distribución determina qué tan uniformemente se aplica la luz en el área.</p><p>Ambos factores son críticos para lograr una iluminación efectiva y utilizable.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de una colocación y distribución adecuadas es proporcionar visibilidad uniforme en todo el espacio de trabajo.</p><p>Esto ayuda a:</p><ul><li>Eliminar áreas oscuras y sombras excesivas</li><li>Mejorar la visibilidad y precisión de las tareas</li><li>Reducir el deslumbramiento y la molestia visual</li><li>Asegurar condiciones de iluminación consistentes</li></ul><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La colocación de iluminación se define por la ubicación y el espaciado de las luminarias.</p><p>La distribución depende del diseño de la luminaria y de cómo se emite la luz.</p><p>Los aspectos clave incluyen:</p><ul><li>Altura de montaje, que afecta el área de cobertura y la intensidad</li><li>Espaciado entre luminarias para asegurar iluminación uniforme</li><li>Ángulo de haz y patrón de luz de la luminaria</li><li>Orientación para evitar deslumbramiento directo y sombras</li></ul><p>Un diseño bien planificado equilibra la cobertura y la intensidad para evitar sobre-iluminar o sub-iluminar áreas específicas.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La colocación y distribución son importantes en:</p><ul><li>Áreas de producción con operaciones continuas</li><li>Almacenes con estanterías y pasillos</li><li>Tableros de control y estaciones de trabajo</li><li>Áreas de mantenimiento que requieren trabajo detallado</li><li>Espacios exteriores con requisitos de cobertura amplia</li></ul><p>Cada aplicación requiere un enfoque diferente según la disposición y los requisitos de la tarea.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li>La uniformidad es más importante que la alta intensidad localizada</li><li>Las sombras deben minimizarse en las áreas de trabajo</li><li>El deslumbramiento debe controlarse para proteger la visibilidad</li><li>La colocación de luminarias debe considerar obstáculos como equipo o estructuras</li><li>La altura de montaje debe coincidir con el tipo de luminaria y el espacio</li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>La iluminación desigual crea fatiga y reduce la eficiencia</li><li>Las luminarias colocadas muy separadas crean zonas oscuras</li><li>Una colocación deficiente puede ocultar detalles o peligros importantes</li><li>La iluminación de tarea debe complementar la iluminación general, no reemplazarla</li><li>Siempre evalúe la iluminación desde el punto de vista del operador</li></ul>',23)])])}const b=i(o,[["render",r]]);export{m as __pageData,b as default};
